n = 42
pi = 3.14159
name = "go"

print(f"{n:5d}")
print(f"{n:05d}")
print(f"{n:b}")
print(f"{n:x}")
print(f"{n:X}")
print(f"{n:o}")
print(f"{1234567:,}")
print(f"{pi:.2f}")
print(f"{pi:10.3f}")
print(f"{pi:.4e}")
print(f"{name:>6}")
print(f"{name:<6}|")
print(f"{name:^6}|")
print(f"{name:*^8}")
print(f"{-n:+d}")
print(f"{n:+d}")
